def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        base_ratio = item / cap
        if base_ratio > 2.0:
            priorities[i] = np.inf
            continue
        score = 1.0
        weight_sum = 0.0
        decay_factor = 1.0
        temp_penalty = 0.0
        mod_mult = 1.0
        for a in range(1, 15):
            factor = np.cos(a * base_ratio) + np.sin(a / (base_ratio + 0.01))
            if a % 2 == 1:
                decay_factor *= 0.98 + 0.005 * a
            else:
                decay_factor *= 1.02 - 0.003 * a
            if (cap + a * 3) % 5 == 0:
                mod_mult *= 1.03
            elif (cap * a) % 8 == 0:
                mod_mult *= 0.97
            if base_ratio < 0.15 * a:
                increment = factor * np.exp(-a / (base_ratio + 1))
            else:
                increment = (np.log1p(a*a) * factor) / (a + base_ratio + 1)
            score += increment * decay_factor
            weight_sum += 1 / (a + 2)
            if a == 7:
                for b in range(1, 8):
                    diff = cap - item * (b**1.7)
                    if diff > 0:
                        if diff % (b+3) == 0:
                            temp_penalty += np.tanh(diff / (b + 5))
                        else:
                            temp_penalty -= np.log1p(abs(diff)) / (b + 4)
                    else:
                        temp_penalty -= abs(diff) ** 1.1 / (b + 3)
            if (cap + a) % 11 == 0:
                score *= 1.05
            if base_ratio > 0.75 and a % 4 == 0:
                score *= 1.07
            if (a % 5 == 2) and (cap % (a + 2) == 0):
                temp_penalty += np.cos(base_ratio * a) * 0.4
            if a == 14:
                if item < cap * 0.5:
                    score *= 1.15
                else:
                    score *= 0.85
        score += temp_penalty * 0.9
        score *= mod_mult
        if score < 0:
            priorities[i] = -score * (np.log1p(cap * 1.5) + np.sqrt(item + 1))
        else:
            if cap > item * 3.5:
                priorities[i] = -score / (np.sqrt(cap) + 2) * (1 + base_ratio**1.5)
            else:
                priorities[i] = -score / (cap + 5) * np.exp(-base_ratio**2.5)
        if base_ratio > 0.9:
            priorities[i] *= 1.18
        elif base_ratio < 0.04:
            priorities[i] *= 0.7
        if cap % 3 == 0:
            priorities[i] *= 1.03
        else:
            priorities[i] *= 0.97
    return priorities
